#define MAX_ARGS 10
#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000.0

// Match the host struct exactly: char[49] + double (with padding for double alignment)
// char[49] is 49 bytes. double requires 8-byte alignment. 
// 49 % 8 = 1. Padding = 7 bytes. Total = 49 + 7 + 8 = 64 bytes.
// In OpenCL, we must replicate this layout.
typedef struct {
    char entry[REC_LENGTH];
    // Explicit padding to match C struct alignment for double on most platforms
    // char[49] ends at index 48. Next is 49. 
    // double needs to start at offset divisible by 8. Next is 56.
    // Padding bytes: 56 - 49 = 7.
    char padding[7];
    double dist;
} neighbor_t;

__kernel void compute_distances(
    const char *sandbox,
    float *z,
    int rec_count,
    float target_lat,
    float target_long)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    const char *rec_iter = sandbox + (i * REC_LENGTH + LATITUDE_POS - 1);

    float tmp_lat = 0.0f;
    float tmp_long = 0.0f;

    // Simple parser for latitude
    int idx = 0;
    float sign = 1.0f;
    float val = 0.0f;
    float frac = 0.0f;
    float divisor = 1.0f;
    int has_dot = 0;

    char c = rec_iter[idx];
    if (c == '-') { 
        sign = -1.0f; 
        idx++; 
        c = rec_iter[idx]; 
    }

    while (c != '\0' && c != ' ' && c != '\n' && c != '\r') {
        if (c == '.') {
            has_dot = 1;
            divisor = 10.0f;
        } else if (c >= '0' && c <= '9') {
            int digit = c - '0';
            if (!has_dot) {
                val = val * 10.0f + (float)digit;
            } else {
                frac = frac + (float)digit / divisor;
                divisor *= 10.0f;
            }
        }
        idx++;
        c = rec_iter[idx];
    }
    tmp_lat = sign * (val + frac);

    // Parse longitude (offset by 5)
    rec_iter += 5;
    idx = 0;
    sign = 1.0f;
    val = 0.0f;
    frac = 0.0f;
    divisor = 1.0f;
    has_dot = 0;

    c = rec_iter[idx];
    if (c == '-') { 
        sign = -1.0f; 
        idx++; 
        c = rec_iter[idx]; 
    }

    while (c != '\0' && c != ' ' && c != '\n' && c != '\r') {
        if (c == '.') {
            has_dot = 1;
            divisor = 10.0f;
        } else if (c >= '0' && c <= '9') {
            int digit = c - '0';
            if (!has_dot) {
                val = val * 10.0f + (float)digit;
            } else {
                frac = frac + (float)digit / divisor;
                divisor *= 10.0f;
            }
        }
        idx++;
        c = rec_iter[idx];
    }
    tmp_long = sign * (val + frac);

    float diff_lat = tmp_lat - target_lat;
    float diff_long = tmp_long - target_long;
    z[i] = sqrt(diff_lat * diff_lat + diff_long * diff_long);
}

__kernel void update_neighbors(
    const float *z,
    const char *sandbox,
    neighbor_t *neighbors,
    int rec_count,
    int k)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    float current_dist = z[i];

    // Find the neighbor with the maximum distance
    double max_dist = -1.0;
    int max_idx = 0;

    for (int j = 0; j < k; j++) {
        if (neighbors[j].dist > max_dist) {
            max_dist = neighbors[j].dist;
            max_idx = j;
        }
    }

    // If current record is closer, replace the furthest neighbor
    if ((double)current_dist < neighbors[max_idx].dist) {
        const char *src = sandbox + (i * REC_LENGTH);
        // Copy entry
        for (int c = 0; c < REC_LENGTH; c++) {
            neighbors[max_idx].entry[c] = src[c];
        }
        // Padding is automatically handled by struct layout, just set dist
        neighbors[max_idx].dist = (double)current_dist;
    }
}
